// ─── TAG ────────────────────────────────────────────────────────
function Tag({ children, v = 'navy' }) {
  const s = {
    navy:   { background: '#1c2d3f', color: '#fff' },
    orange: { background: '#f5a623', color: '#1c2d3f' },
    light:  { background: '#f0f2f7', color: '#1c2d3f', border: '1px solid #e2e8f0' },
  }
  return (
    <span style={{
      fontFamily: 'DM Mono, monospace', fontSize: '0.66rem',
      padding: '2px 8px', borderRadius: 3, lineHeight: 1.6,
      display: 'inline-block', ...s[v],
    }}>{children}</span>
  )
}

